import{_ as s,o as n,c as p,a1 as e}from"./chunks/framework.BKJzsOC1.js";const u=JSON.parse('{"title":"第二章：盘前地图与开盘环境分类","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/02-premarket-map-and-opening-regimes.md","filePath":"trading/intraday-entry/02-premarket-map-and-opening-regimes.md"}'),i={name:"trading/intraday-entry/02-premarket-map-and-opening-regimes.md"};function t(l,a,d,c,h,o){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="第二章-盘前地图与开盘环境分类" tabindex="-1">第二章：盘前地图与开盘环境分类 <a class="header-anchor" href="#第二章-盘前地图与开盘环境分类" aria-label="Permalink to &quot;第二章：盘前地图与开盘环境分类&quot;">​</a></h1><blockquote><p>盘前的任务不是预测全天涨跌，而是提前定义：价格到了哪里需要观察，出现什么行为才允许交易。</p></blockquote><h2 id="一、盘前只做一件事-建立地图" tabindex="-1">一、盘前只做一件事：建立地图 <a class="header-anchor" href="#一、盘前只做一件事-建立地图" aria-label="Permalink to &quot;一、盘前只做一件事：建立地图&quot;">​</a></h2><p>盘前分析的重点不是给出一个方向，而是把可能产生反应的区域标出来。</p><p>建议优先标记：</p><ul><li>前一交易日高点和低点</li><li>盘前高点和低点</li><li>开盘价</li><li>第一根 10 分钟 K 线的高点和低点</li><li>VWAP 可能所在的位置</li><li>主要支撑、阻力和流动性集中区</li><li>重要整数位</li><li>当天的新闻、数据和财报风险</li></ul><p>可以把这些位置分成三层：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>执行区：距离当前价格较近，今天可能直接测试</span></span>
<span class="line"><span>目标区：距离适中，可作为第一目标或第二目标</span></span>
<span class="line"><span>背景区：距离较远，只用于理解大方向，不作为直接入场理由</span></span></code></pre></div><p>盘前不需要把所有历史线都放进图里。实际执行时，通常只保留最近的 2—3 个上方和下方关键位置，避免图表过度复杂。</p><h2 id="二、不同工具承担不同任务" tabindex="-1">二、不同工具承担不同任务 <a class="header-anchor" href="#二、不同工具承担不同任务" aria-label="Permalink to &quot;二、不同工具承担不同任务&quot;">​</a></h2><p>指标和图表工具不应被混合成一个“预测按钮”。每个工具应该有明确职责：</p><table tabindex="0"><thead><tr><th>工具</th><th>主要问题</th><th>不应该承担的任务</th></tr></thead><tbody><tr><td>GEX、墙位、流动性区</td><td>价格可能在哪里减速、吸附或反应？</td><td>直接预测涨跌方向</td></tr><tr><td>前高、前低、ORB</td><td>当前价格是否正在突破重要结构？</td><td>突破第一根直接追单</td></tr><tr><td>VWAP</td><td>当前持仓是否处在相对有利的一侧？</td><td>把它当成必然反转线</td></tr><tr><td>成交量、资金流</td><td>这次突破是否得到持续参与？</td><td>只看单笔大单就跟随</td></tr><tr><td>1 分钟 K 线</td><td>如何执行和管理仓位？</td><td>单独预测全天走势</td></tr><tr><td>3 分钟、5 分钟 K 线</td><td>当前结构是否连续？</td><td>忽略大级别位置</td></tr></tbody></table><p>科学的使用顺序是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置 → 价格结构 → 回踩/拒绝 → VWAP → 量价与资金流 → 辅助指标</span></span></code></pre></div><p>后面的指标只能提高或降低把握，不能推翻前面的价格事实。</p><h2 id="三、开盘阶段-先观察-再分类" tabindex="-1">三、开盘阶段：先观察，再分类 <a class="header-anchor" href="#三、开盘阶段-先观察-再分类" aria-label="Permalink to &quot;三、开盘阶段：先观察，再分类&quot;">​</a></h2><p>开盘最容易出现噪音、扫损和情绪化突破。前 5—10 分钟的主要任务是观察，而不是急于完成第一笔交易。</p><p>开盘需要记录：</p><ol><li>第一段价格区间的高点和低点。</li><li>价格是否快速离开开盘区间。</li><li>突破后是否回到原区间。</li><li>高点和低点是否开始持续推进。</li><li>VWAP 是否有明显斜率，价格是否持续位于同一侧。</li><li>关键位置附近是否出现拒绝或接受。</li></ol><p>开盘第一根 10 分钟 K 线可以提供早盘边界，但它不是追单信号：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破 ORB → 不追第一根 → 等回踩 → 回踩在区间外 → 再次启动</span></span></code></pre></div><h2 id="四、三种主要市场环境" tabindex="-1">四、三种主要市场环境 <a class="header-anchor" href="#四、三种主要市场环境" aria-label="Permalink to &quot;四、三种主要市场环境&quot;">​</a></h2><h3 id="_1-趋势环境" tabindex="-1">1. 趋势环境 <a class="header-anchor" href="#_1-趋势环境" aria-label="Permalink to &quot;1. 趋势环境&quot;">​</a></h3><p>常见特征：</p><ul><li>高点和低点持续向同一方向推进</li><li>多头回踩不跌回旧区间，空头反抽不上旧区间</li><li>价格大部分时间位于 VWAP 同一侧</li><li>回踩浅，重新启动速度较快</li><li>关键位置被突破后，市场愿意在新区间停留</li></ul><p>趋势环境的交易方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只做顺势回踩</span></span>
<span class="line"><span>止损放在回踩结构外</span></span>
<span class="line"><span>目标看下一个关键位置</span></span>
<span class="line"><span>到目标前分批兑现</span></span></code></pre></div><p>趋势日最容易犯的错误，是把正常回踩误判成反转，或者在已经远离结构后追单。</p><h3 id="_2-震荡或吸附环境" tabindex="-1">2. 震荡或吸附环境 <a class="header-anchor" href="#_2-震荡或吸附环境" aria-label="Permalink to &quot;2. 震荡或吸附环境&quot;">​</a></h3><p>常见特征：</p><ul><li>开盘价或 VWAP 被反复穿越</li><li>上下关键位置都出现反应，但没有持续突破</li><li>高点和低点没有明显推进</li><li>价格围绕中轴反复波动</li><li>关键节点被多次测试却没有形成接受</li></ul><p>震荡环境的交易方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中间区域不做</span></span>
<span class="line"><span>上沿等待拒绝</span></span>
<span class="line"><span>下沿等待拒绝</span></span>
<span class="line"><span>目标看回中轴或对侧边界</span></span>
<span class="line"><span>突破并回踩站稳后，才切换成趋势打法</span></span></code></pre></div><p>震荡日最重要的不是增加指标，而是减少交易次数。中间位置没有足够的风险收益优势。</p><h3 id="_3-失败突破或反转环境" tabindex="-1">3. 失败突破或反转环境 <a class="header-anchor" href="#_3-失败突破或反转环境" aria-label="Permalink to &quot;3. 失败突破或反转环境&quot;">​</a></h3><p>常见特征：</p><ul><li>价格先突破开盘区间或前高/前低</li><li>突破后快速回到原区间</li><li>原来的突破方向无法再次站回关键位</li><li>随后出现反抽失败或回踩失败</li><li>结构开始向反方向推进</li></ul><p>失败突破的交易方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一次冲出：只观察</span></span>
<span class="line"><span>快速回到原区间：突破降级</span></span>
<span class="line"><span>反抽/回踩再次失败：反向建仓</span></span>
<span class="line"><span>止损放在失败突破的极值外</span></span>
<span class="line"><span>目标看中轴、开盘区间另一侧或下一个节点</span></span></code></pre></div><p>不能因为一次长影线就立即反手。长影线只是拒绝的可能，后续收回和再次测试失败才是确认。</p><h2 id="五、用决策树分类-而不是凭感觉分类" tabindex="-1">五、用决策树分类，而不是凭感觉分类 <a class="header-anchor" href="#五、用决策树分类-而不是凭感觉分类" aria-label="Permalink to &quot;五、用决策树分类，而不是凭感觉分类&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[价格到达关键位置] --&gt; B{是否有效突破或收回?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- 否 --&gt; C[继续观察；中间区域不交易]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- 是 --&gt; D{回踩后是否留在新区间?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D -- 是 --&gt; E[趋势候选：顺势回踩建仓]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D -- 否 --&gt; F{是否快速回到原区间?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F -- 是 --&gt; G[失败突破候选：等待反抽/回踩失败]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F -- 否 --&gt; C</span></span></code></pre></div><p>这棵决策树的核心不是预测，而是根据价格最终“接受在哪个区间”来决定打法。</p><h2 id="六、如何处理不确定的开盘" tabindex="-1">六、如何处理不确定的开盘 <a class="header-anchor" href="#六、如何处理不确定的开盘" aria-label="Permalink to &quot;六、如何处理不确定的开盘&quot;">​</a></h2><p>如果开盘后出现以下情况，应当降低频率和仓位：</p><ul><li>价格在两个关键位置之间来回穿越</li><li>VWAP 几乎没有斜率</li><li>突破没有后续跟随</li><li>价格和主要指数不同步</li><li>事件风险即将发布</li><li>只能找到方向，找不到明确失效点</li></ul><p>这时最合理的选择是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>等待价格到达边界</span></span>
<span class="line"><span>→ 等待拒绝或接受</span></span>
<span class="line"><span>→ 重新计算目标与失效</span></span>
<span class="line"><span>→ 小仓或观望</span></span></code></pre></div><p>没有清晰环境时，空仓不是错过机会，而是避免在低质量区域消耗风险预算。</p><h2 id="七、第二章执行表" tabindex="-1">七、第二章执行表 <a class="header-anchor" href="#七、第二章执行表" aria-label="Permalink to &quot;七、第二章执行表&quot;">​</a></h2><h3 id="盘前" tabindex="-1">盘前 <a class="header-anchor" href="#盘前" aria-label="Permalink to &quot;盘前&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上方最近关键位：</span></span>
<span class="line"><span>下方最近关键位：</span></span>
<span class="line"><span>开盘价：</span></span>
<span class="line"><span>盘前高低：</span></span>
<span class="line"><span>ORB 高低：</span></span>
<span class="line"><span>VWAP：</span></span>
<span class="line"><span>事件风险：</span></span></code></pre></div><h3 id="开盘后" tabindex="-1">开盘后 <a class="header-anchor" href="#开盘后" aria-label="Permalink to &quot;开盘后&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前环境：趋势 / 震荡 / 失败突破 / 未分类</span></span>
<span class="line"><span>价格是否离开开盘区间：</span></span>
<span class="line"><span>是否完成回踩：</span></span>
<span class="line"><span>VWAP 是否同侧：</span></span>
<span class="line"><span>主要指数是否同步：</span></span>
<span class="line"><span>上方第一目标：</span></span>
<span class="line"><span>下方第一目标：</span></span>
<span class="line"><span>不做条件：</span></span></code></pre></div><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><p>盘前地图负责回答“在哪里观察”，开盘结构负责回答“今天是什么环境”，回踩或失败测试负责回答“是否可以建仓”。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>盘前画位置</span></span>
<span class="line"><span>→ 开盘看结构</span></span>
<span class="line"><span>→ 分类市场环境</span></span>
<span class="line"><span>→ 选择对应打法</span></span>
<span class="line"><span>→ 等待确认后建仓</span></span></code></pre></div><p>最重要的纪律是：</p><blockquote><p>不要用趋势打法交易震荡，也不要用抄底摸顶的方式交易趋势。</p></blockquote>`,59)])])}const g=s(i,[["render",t]]);export{u as __pageData,g as default};
